19	interface Habit {
20	  id: string;
21	  title: string;
22	  description: string | null;
23	  domainId: string;
24	  unit: string;
25	  targetValue: number;
26	  frequency: string;
27	  isActive: boolean;
28	}
29	
30	export default function HabitsPage() {
31	  const [habits, setHabits] = useState<Habit[]>([]);
32	  const [loading, setLoading] = useState(true);
33	  const [showForm, setShowForm] = useState(false);
34	  const [editId, setEditId] = useState<string | null>(null);
35	  const [form, setForm] = useState({
36	    title: "", description: "", domainIdx: 0, unit: "次",
37	    targetValue: 1, frequency: "daily",
38	  });
39	
40	  // Domain management state
41	  const [showDomainManager, setShowDomainManager] = useState(false);
42	  const [domainManagerView, setDomainManagerView] = useState<"list" | "new" | "edit">("list");
43	  const [domainForm, setDomainForm] = useState<Domain>({ name: "", icon: "💪", color: "#ef4444" });
44	  const [editingDomainName, setEditingDomainName] = useState<string | null>(null);
45	
46	  useDidShow(() => { fetchHabits(); });
47	
48	  async function fetchHabits() {
49	    setHabits(await apiFetch("/api/habits"));
50	    setLoading(false);
51	  }
52	
53	  function openNew() {
54	    setEditId(null);
55	    setForm({ title: "", description: "", domainIdx: 0, unit: "次", targetValue: 1, frequency: "daily" });
56	    setShowForm(true);
57	  }
58	
59	  function openEdit(h: Habit) {
60	    setEditId(h.id);
61	    const domains = getDomains();
62	    const idx = domains.findIndex(d => d.name === h.domainId);
63	    setForm({
64	      title: h.title,
65	      description: h.description || "",
66	      domainIdx: idx >= 0 ? idx : domains.length - 1,
67	      unit: h.unit,
68	      targetValue: h.targetValue,
69	      frequency: h.frequency,
70	    });
71	    setShowForm(true);
72	  }
73	
74	  async function handleSave() {
75	    const domains = getDomains();
76	    const body = { ...form, domainId: domains[form.domainIdx].name };
77	    if (editId) {
78	      await apiFetch("/api/habits", { method: "PUT", body: JSON.stringify({ id: editId, ...body }) });
79	    } else {
80	      await apiFetch("/api/habits", { method: "POST", body: JSON.stringify(body) });
81	    }
82	    setShowForm(false);
83	    fetchHabits();
84	  }
85	
86	  async function deleteHabit(id: string) {
87	    await apiFetch("/api/habits", { method: "DELETE", body: JSON.stringify({ id }) });
88	    fetchHabits();
89	  }
90	
91	  async function toggleActive(id: string, current: boolean) {
92	    await apiFetch("/api/habits", { method: "PUT", body: JSON.stringify({ id, isActive: !current }) });
93	    fetchHabits();
94	  }
95	
96	  // ---- Domain management handlers ----
97	
98	  function openDomainManager() {
99	    setShowForm(false);
100	    setDomainManagerView("list");
101	    setDomainForm({ name: "", icon: "💪", color: "#ef4444" });
102	    setEditingDomainName(null);
103	    setShowDomainManager(true);
104	  }
105	
106	  function openNewDomain() {
107	    setDomainForm({ name: "", icon: "💪", color: "#ef4444" });
108	    setDomainManagerView("new");
109	  }
110	
111	  function openEditDomain(domain: Domain) {
112	    setEditingDomainName(domain.name);
113	    setDomainForm({ name: domain.name, icon: domain.icon, color: domain.color });
114	    setDomainManagerView("edit");
115	  }
116	
117	  function handleDomainSave() {
118	    const name = domainForm.name.trim();
119	    if (!name) return;
120	
121	    const userDomains = getDomains().filter(d => d.name !== UNCATEGORIZED.name);
122	
123	    if (domainManagerView === "new") {
124	      if (userDomains.some(d => d.name === name)) {
125	        showModal({ title: "提示", content: "该领域名称已存在", showCancel: false });
126	        return;
127	      }
128	      userDomains.push({ name, icon: domainForm.icon, color: domainForm.color });
129	    } else if (domainManagerView === "edit") {
130	      const idx = userDomains.findIndex(d => d.name === editingDomainName);
131	      if (idx === -1) return;
132	
133	      if (name !== editingDomainName && userDomains.some(d => d.name === name)) {
134	        showModal({ title: "提示", content: "该领域名称已存在", showCancel: false });
135	        return;
136	      }
137	
138	      const oldName = userDomains[idx].name;
139	      userDomains[idx] = { name, icon: domainForm.icon, color: domainForm.color };
140	
141	      // If domain renamed, update all habits under old name
142	      if (name !== oldName) {
143	        (async () => {
144	          for (const h of habits.filter(h => h.domainId === oldName)) {
145	            await apiFetch("/api/habits", { method: "PUT", body: JSON.stringify({ id: h.id, domainId: name }) });
146	          }
147	          fetchHabits();
148	        })();
149	      }
150	    }
151	
152	    saveDomains(userDomains);
153	    setDomainManagerView("list");
154	    setEditingDomainName(null);
155	  }
156	
157	  async function handleDeleteDomain(domain: Domain) {
158	    const count = habits.filter(h => h.domainId === domain.name).length;
159	    const res = await showModal({
160	      title: "删除领域",
161	      content: `确定删除"${domain.name}"吗？其下 ${count} 个习惯将移入"未分类"。`,
162	    });
163	
164	    if (!res.confirm) return;
165	
166	    const userDomains = getDomains()
167	      .filter(d => d.name !== UNCATEGORIZED.name && d.name !== domain.name);
168	    saveDomains(userDomains);
169	
170	    // Move habits to 未分类
171	    for (const h of habits.filter(h => h.domainId === domain.name)) {
172	      await apiFetch("/api/habits", { method: "PUT", body: JSON.stringify({ id: h.id, domainId: UNCATEGORIZED.name }) });
173	    }
174	
175	    fetchHabits();
176	  }
177	
178	  const domains = getDomains();
179	
180	  return (
181	    <View className="page">
182	      <View className="page-header">
183	        <View>
184	          <Text className="page-title">习惯管理</Text>
185	          <Text className="page-subtitle">管理你的每日修炼清单</Text>
186	        </View>
187	        <View className="add-btn" onClick={openNew}><Text>+</Text></View>
188	      </View>
189	
190	      <View className="domain-manager-entry" onClick={openDomainManager}>
191	        <Text>管理分类</Text>
192	      </View>
193	
194	      {domains.map((domain) => {
195	        const domainHabits = habits.filter((h) => h.domainId === domain.name);
196	        return (
197	          <View key={domain.name}>
198	            <Text className="domain-title">{domain.icon} {domain.name}</Text>
199	            {domainHabits.map((habit) => (
200	              <View key={habit.id} className={`habit-card ${!habit.isActive ? "inactive" : ""}`}>
201	                <View className="habit-info">
202	                  <Text className="habit-name">{habit.title}</Text>
203	                  {habit.description && <Text className="habit-desc">{habit.description}</Text>}
204	                  <View className="habit-meta">
205	                    <Text>{habit.frequency === "daily" ? "每日" : habit.frequency}</Text>
206	                    <Text> · </Text>
207	                    <Text>目标 {habit.targetValue}{habit.unit}</Text>
208	                  </View>
209	                </View>
210	                <View className="habit-actions">
211	                  <Text className="action-btn" onClick={() => toggleActive(habit.id, habit.isActive)}>
212	                    {habit.isActive ? "停用" : "启用"}
213	                  </Text>
214	                  <Text className="action-btn" onClick={() => openEdit(habit)}>编辑</Text>
215	                  <Text className="action-btn danger" onClick={() => deleteHabit(habit.id)}>删除</Text>
216	                </View>
217	              </View>
218	            ))}
219	          </View>
220	        );
221	      })}
222	
223	      {!loading && habits.length === 0 && (
224	        <View className="empty"><Text>还没有习惯，点右上角 + 开始</Text></View>
225	      )}
226	
227	      {/* ---- Habit Form Modal ---- */}
228	      {showForm && (
229	        <View className="modal-mask" onClick={() => setShowForm(false)}>
230	          <View className="modal" onClick={(e) => e.stopPropagation()}>
231	            <Text className="modal-title">{editId ? "编辑习惯" : "新增习惯"}</Text>
232	
233	            <View className="form-group">
234	              <Text className="form-label">名称</Text>
235	              <Input className="form-input" placeholder="如：晨跑30分钟" value={form.title} onInput={(e) => setForm({ ...form, title: e.detail.value })} />
236	            </View>
237	
238	            <View className="form-group">
239	              <Text className="form-label">描述</Text>
240	              <Input className="form-input" placeholder="具体怎么做" value={form.description} onInput={(e) => setForm({ ...form, description: e.detail.value })} />
241	            </View>
242	
243	            <View className="form-row">
244	              <View className="form-group flex-1">
245	                <Text className="form-label">领域</Text>
246	                <Picker mode="selector" range={domains.map(d => d.icon + " " + d.name)} value={form.domainIdx} onChange={(e) => setForm({ ...form, domainIdx: +e.detail.value })}>
247	                  <View className="form-picker">{domains[form.domainIdx].icon} {domains[form.domainIdx].name}</View>
248	                </Picker>
249	              </View>
250	              <View className="form-group flex-1">
251	                <Text className="form-label">频率</Text>
252	                <Picker mode="selector" range={["每日", "每周", "工作日"]} value={form.frequency === "daily" ? 0 : form.frequency === "weekly" ? 1 : 2} onChange={(e) => setForm({ ...form, frequency: ["daily", "weekly", "weekday"][+e.detail.value] })}>
253	                  <View className="form-picker">{form.frequency === "daily" ? "每日" : form.frequency === "weekly" ? "每周" : "工作日"}</View>
254	                </Picker>
255	              </View>
256	            </View>
257	
258	            <View className="form-row">
259	              <View className="form-group flex-1">
260	                <Text className="form-label">目标值</Text>
261	                <Input className="form-input" type="number" value={String(form.targetValue)} onInput={(e) => setForm({ ...form, targetValue: +e.detail.value || 1 })} />
262	              </View>
263	              <View className="form-group flex-1">
264	                <Text className="form-label">单位</Text>
265	                <Input className="form-input" placeholder="次/分钟/页" value={form.unit} onInput={(e) => setForm({ ...form, unit: e.detail.value })} />
266	              </View>
267	            </View>
268	
269	            <View className="form-buttons">
270	              <View className="btn-cancel" onClick={() => setShowForm(false)}><Text>取消</Text></View>
271	              <View className="btn-save" onClick={handleSave}><Text>{editId ? "保存" : "添加"}</Text></View>
272	            </View>
273	          </View>
274	        </View>
275	      )}
276	
277	      {/* ---- Domain Manager Modal ---- */}
278	      {showDomainManager && (
279	        <View className="modal-mask" onClick={() => setShowDomainManager(false)}>
280	          <View className="modal" onClick={(e) => e.stopPropagation()}>
281	
282	            {/* List View */}
283	            {domainManagerView === "list" && (
284	              <>
285	                <View className="modal-header-row">
286	                  <Text className="modal-title">管理分类</Text>
287	                  <Text className="modal-add-btn" onClick={openNewDomain}>+ 新增</Text>
288	                </View>
289	
290	                {domains.map((domain) => {
291	                  const isSystem = domain.name === UNCATEGORIZED.name;
292	                  return (
293	                    <View key={domain.name} className={`domain-list-item ${isSystem ? "system" : ""}`}>
294	                      <Text className="domain-list-icon" style={{ color: domain.color }}>{domain.icon}</Text>
295	                      <Text className="domain-list-name">{domain.name}</Text>
296	                      {isSystem ? (
297	                        <Text className="domain-list-tag">系统内置</Text>
298	                      ) : (
299	                        <View className="domain-list-actions">
300	                          <Text className="domain-list-btn" onClick={() => openEditDomain(domain)}>编辑</Text>
301	                          <Text className="domain-list-btn danger" onClick={() => handleDeleteDomain(domain)}>删除</Text>
302	                        </View>
303	                      )}
304	                    </View>
305	                  );
306	                })}
307	
308	                <View className="form-buttons">
309	                  <View className="btn-cancel" onClick={() => setShowDomainManager(false)}><Text>关闭</Text></View>
310	                </View>
311	              </>
312	            )}
313	
314	            {/* New / Edit Form View */}
315	            {(domainManagerView === "new" || domainManagerView === "edit") && (
316	              <>
317	                <Text className="modal-title">{domainManagerView === "new" ? "新增分类" : "编辑分类"}</Text>
318	
319	                <View className="form-group">
320	                  <Text className="form-label">名称</Text>
321	                  <Input
322	                    className="form-input"
323	                    placeholder="分类名称"
324	                    value={domainForm.name}
325	                    onInput={(e) => setDomainForm({ ...domainForm, name: e.detail.value })}
326	                  />
327	                </View>
328	
329	                <View className="form-group">
330	                  <Text className="form-label">图标</Text>
331	                  <View className="emoji-grid">
332	                    {EMOJI_OPTIONS.map((emoji) => (
333	                      <View
